package main

import (
    "fmt"
    "html"
    "net/http"
    "strings"
    "time"
)

// Product represents a product in the search results
type Product struct {
    ID          int
    Name        string
    Price       float64
    Description string
}

// AnalyticsData represents search analytics data
type AnalyticsData struct {
    Keyword     string    `json:"keyword"`
    Timestamp   time.Time `json:"timestamp"`
    UserAgent   string    `json:"user_agent"`
    IPAddress  string    `json:"ip_address"`
}

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Parse query parameters
    query := r.URL.Query()
    keyword := query.Get("keyword")

    // Log analytics data
    logAnalytics(r, keyword)

    // Generate HTML response
    htmlContent := generateHTML(keyword)
    fmt.Fprint(w, htmlContent)
}

// logAnalytics logs search analytics data
func logAnalytics(r *http.Request, keyword string) {
    analytics := AnalyticsData{
        Keyword:    keyword,
        Timestamp:  time.Now(),
        UserAgent:  r.UserAgent(),
        IPAddress: getIPAddress(r),
    }

    // In a real application, you would save this to a database or log file
    // For this example, we'll just print to console
    fmt.Printf("Search Analytics: Keyword='%s', Time=%s, UserAgent='%s', IP=%s\n",
        analytics.Keyword,
        analytics.Timestamp.Format("2006-01-02 15:04:05"),
        analytics.UserAgent,
        analytics.IPAddress)
}

// getIPAddress extracts the client IP address from the request
func getIPAddress(r *http.Request) string {
    // Check for X-Forwarded-For header (common in proxy setups)
    forwarded := r.Header.Get("X-Forwarded-For")
    if forwarded != "" {
        // Take the first IP in the list
        ips := strings.Split(forwarded, ",")
        return strings.TrimSpace(ips[0])
    }

    // Fall back to RemoteAddr
    return strings.Split(r.RemoteAddr, ":")[0]
}

// generateHTML generates the HTML page for search results
func generateHTML(keyword string) string {
    // Escape the keyword to prevent XSS attacks
    escapedKeyword := html.EscapeString(keyword)

    // Sample products for demonstration
    products := []Product{
        {ID: 1, Name: "Wireless Headphones", Price: 99.99, Description: "Noise-cancelling wireless headphones"},
        {ID: 2, Name: "Smart Watch", Price: 199.99, Description: "Fitness tracker with heart rate monitor"},
        {ID: 3, Name: "Laptop Backpack", Price: 49.99, Description: "Water-resistant laptop backpack"},
    }

    // Filter products based on keyword (case-insensitive)
    var filteredProducts []Product
    if keyword != "" {
        lowerKeyword := strings.ToLower(keyword)
        for _, product := range products {
            if strings.Contains(strings.ToLower(product.Name), lowerKeyword) ||
               strings.Contains(strings.ToLower(product.Description), lowerKeyword) {
                filteredProducts = append(filteredProducts, product)
            }
        }
    } else {
        // If no keyword provided, show all products
        filteredProducts = products
