package main

import (
	"encoding/json"
	"fmt"
	"html"
	"net/http"
	"time"
)

// AnalyticsEvent represents a search analytics event
type AnalyticsEvent struct {
	Keyword    string    `json:"keyword"`
	Timestamp  time.Time `json:"timestamp"`
	UserAgent  string    `json:"user_agent"`
	RemoteAddr string    `json:"remote_addr"`
}

// AnalyticsStore stores search analytics events (in-memory for simplicity)
var AnalyticsStore []AnalyticsEvent

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get search keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Record analytics event
	recordAnalytics(r, keyword)

	// Generate HTML response
	htmlContent := generateHTML(keyword)

	// Write response
	fmt.Fprint(w, htmlContent)
}

// recordAnalytics records search analytics data
func recordAnalytics(r *http.Request, keyword string) {
	if keyword == "" {
		return
	}

	event := AnalyticsEvent{
		Keyword:    keyword,
		Timestamp:  time.Now(),
		UserAgent:  r.UserAgent(),
		RemoteAddr: r.RemoteAddr,
	}

	AnalyticsStore = append(AnalyticsStore, event)

	// Log analytics event (optional)
	fmt.Printf("Analytics: Search for '%s' from %s at %s\n", 
		keyword, r.RemoteAddr, event.Timestamp.Format(time.RFC3339))
}

// generateHTML generates the HTML response with search results
func generateHTML(keyword string) string {
	// Escape keyword for safe HTML display
	escapedKeyword := html.EscapeString(keyword)

	// Default message if no keyword provided
	if escapedKeyword == "" {
		return `<!DOCTYPE html>
<html>
<head>
    <title>Product Search</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .container { max-width: 800px; margin: 0 auto; }
        .search-box { margin: 20px 0; padding: 10px; border: 1px solid #ddd; }
        .results { margin-top: 30px; }
        .product { border: 1px solid #ccc; padding: 15px; margin: 10px 0; }
        .analytics { margin-top: 40px; padding: 15px; background: #f5f5f5; }
    </style>
</head>
<body>
    <div class="container">
        <h2>Product Search</h2>
        <div class="search-box">
            <p>Please provide a search keyword using the URL parameter: ?keyword=your_search_term</p>
            <p>Example: <a href="/search?keyword=laptop">/search?keyword=laptop</a></p>
        </div>
        <div class="analytics">
            <h3>Search Analytics</h3>
            <p>Total searches recorded: ` + fmt.Sprintf("%d", len(AnalyticsStore)) + `</p>
            <p><a href="/analytics">View detailed analytics</a></p>
        </div>
    </div>
</body>
</html>`
	}

	// Generate search results page with analytics
	return `<!DOCTYPE html>
<html>
<head>
    <title>Search Results: ` + escapedKeyword + `</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .container { max-width: 800px; margin: 0 auto; }
        .search-box { margin: 20px 0; padding: 10px; border: 1px solid #ddd; }
        .results { margin-top: 30px; }
        .product { border: 1px solid #ccc; padding: 15px; margin: 10px 0; }
        .analytics { margin-top: 40px; padding: 15px; background: #f5f5f5; }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: ` + escapedKeyword + `</h2>

        <div class="search-box">
            <p>Showing results for: <strong>` + escapedKeyword + `</strong></p>
            <p><a href="/search">New Search</a></p>
        </div>

        <div class="results">
            <h3>Found 3 products matching "` + escapedKeyword + `":</h3>

            <div class="product">
                <h4>Product A - ` + escapedKeyword + ` Edition</h4>
                <p>High-quality ` + escapedKeyword + ` with advanced features.</p>
                <p>Price: $299.99</p>
            </div>

            <div class="product">
                <h4>Premium ` + escapedKeyword + ` Pro</h4>
                <p>Professional grade ` + escapedKeyword + ` for demanding users.</p>
                <p>Price: $499.99</p>
            </div>

            <div class="product">
                <h4>Basic ` + escapedKeyword + ` Starter</h4>
                <p>Entry-level ` + escapedKeyword + ` for beginners.</p>
                <p>Price: $99.99</p>
            </div>
        </div>

        <div class="analytics">
            <h3>Search Analytics</h3>
            <p>Your search has been recorded for analytics purposes.</p>
            <p>Total searches recorded: ` + fmt.Sprintf("%d", len(AnalyticsStore)) + `</p>
            <p><a href="/analytics">View detailed analytics</a></p>
        </div>
    </div>
</body>
</html>`
}

// HandleAnalytics displays search analytics data
func HandleAnalytics(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	// Return analytics data as JSON
	jsonData, err := json.MarshalIndent(AnalyticsStore, "", "  ")
	if err != nil {
		http.Error(w, "Error generating analytics", http.StatusInternalServerError)
		return
	}

	w.Write(jsonData)
}

func main() {
	// Initialize analytics store
	AnalyticsStore = make([]AnalyticsEvent, 0)

	// Register handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", HandleAnalytics)

	// Start server
	fmt.Println("Server starting on http://localhost:8080")
	fmt.Println("Try these URLs:")
	fmt.Println("  http://localhost:8080/search")
	fmt.Println("  http://localhost:8080/search?keyword=laptop")
	fmt.Println("  http://localhost:8080/search?keyword=phone")
	fmt.Println("  http://localhost:8080/analytics")

	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

