            </div>
        </div>

        <div class="analytics">
            <h3>Search Analytics</h3>
            <p><strong>Keyword:</strong> %s</p>
            <p><strong>Total searches for this keyword:</strong> %d</p>
            <p><strong>Your IP:</strong> %s</p>
            <p><strong>Search time:</strong> %s</p>
        </div>

        <div class="back-link">
