		getAnalyticsCount(keyword),
		r.RemoteAddr,
		time.Now().Format("2006-01-02 15:04:05"),
		getAnalyticsHTML())
}

// recordAnalytics records search analytics data
func recordAnalytics(keyword string, r *http.Request) {
	analytics := &SearchAnalytics{
		Keyword:    keyword,
		Timestamp:  time.Now(),
		UserAgent:  r.UserAgent(),
		RemoteAddr: r.RemoteAddr,
	}

	// Send analytics to channel for async processing
	select {
	case analyticsChan <- analytics:
		// Successfully sent to channel
	default:
		// Channel full, analytics might be dropped in high traffic
	}
}

// processAnalytics processes analytics from the channel
func processAnalytics() {
	for analytics := range analyticsChan {
		key := analytics.Keyword

		if existing, exists := analyticsStore[key]; exists {
			existing.SearchCount++
			existing.Timestamp = analytics.Timestamp
		} else {
			analytics.SearchCount = 1
			analyticsStore[key] = analytics
		}
	}
}

// getAnalyticsCount returns the search count for a keyword
func getAnalyticsCount(keyword string) int {
	if analytics, exists := analyticsStore[keyword]; exists {
		return analytics.SearchCount
	}
	return 0
}

// getAnalyticsHTML returns HTML representation of analytics data
func getAnalyticsHTML() string {
	if len(analyticsStore) == 0 {
		return "<p>No search analytics available yet.</p>"
	}

	htmlStr := "<ul>"
	for keyword, analytics := range analyticsStore {
		escapedKeyword := html.EscapeString(keyword)
		htmlStr += fmt.Sprintf(`<li><strong>%s</strong>: %d searches (last: %s)</li>`, 
			escapedKeyword, 
			analytics.SearchCount, 
			analytics.Timestamp.Format("2006-01-02 15:04:05"))
	}
	htmlStr += "</ul>"
	return htmlStr
}

// getAnalyticsJSON returns JSON representation of analytics data
func getAnalyticsJSON(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	analyticsList := make([]*SearchAnalytics, 0, len(analyticsStore))
	for _, analytics := range analyticsStore {
		analyticsList = append(analyticsList, analytics)
	}

	json.NewEncoder(w).Encode(analyticsList)
}

func main() {
	// Start analytics processor
	go processAnalytics()

	// Register handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", getAnalyticsJSON)

	// Root redirect to search
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		http.Redirect(w, r, "/search", http.StatusFound)
	})

	// Start server
	fmt.Println("Server starting on http://localhost:8080")
	fmt.Println("Endpoints:")
	fmt.Println("  GET /search?keyword=... - Search products")
	fmt.Println("  GET /analytics - Get analytics data (JSON)")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

