func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS attacks
	// First, escape any HTML special characters
	sanitizedKeyword := html.EscapeString(keyword)

	// Optional: Trim excessive whitespace to prevent response size attacks
	sanitizedKeyword = strings.TrimSpace(sanitizedKeyword)

	// Limit keyword length to prevent DoS through large responses
