type AnalyticsData struct {
    Keyword     string    `json:"keyword"`
    Timestamp   time.Time `json:"timestamp"`
    UserAgent   string    `json:"user_agent"`
    IPAddress  string    `json:"ip_address"`
}

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Parse query parameters
    query := r.URL.Query()
    keyword := query.Get("keyword")

    // If no keyword provided, show empty search results
    if keyword == "" {
        keyword = "No keyword provided"
    }

    // Escape the keyword for safe HTML display
    escapedKeyword := html.EscapeString(keyword)

    // Collect analytics data
    analytics := AnalyticsData{
        Keyword:    keyword,
        Timestamp:  time.Now(),
        UserAgent:  r.UserAgent(),
        IPAddress: r.RemoteAddr,
    }

    // Log analytics (in production, you would store this in a database)
    // For this example, we'll just include it in the HTML comments
    analyticsHTML := formatAnalyticsHTML(analytics)

    // Generate HTML response
    htmlContent := generateHTML(escapedKeyword, analyticsHTML)

    // Write the response
    w.Write([]byte(htmlContent))
}

// formatAnalyticsHTML formats analytics data as HTML comments
func formatAnalyticsHTML(data AnalyticsData) string {
    return `<!--
