// Product represents a product in the search results
type Product struct {
	Name     string
	Category string
	Price    float64
}

// simulateProductSearch returns mock products based on keyword
func simulateProductSearch(keyword string) []Product {
	// Mock product database
	allProducts := []Product{
		{"Laptop Pro", "Electronics", 1299.99},
		{"Wireless Mouse", "Electronics", 29.99},
		{"Coffee Maker", "Home Appliances", 89.99},
		{"Running Shoes", "Sports", 79.99},
		{"Smartphone X", "Electronics", 899.99},
		{"Desk Chair", "Furniture", 199.99},
		{"Bluetooth Headphones", "Electronics", 149.99},
		{"Yoga Mat", "Sports", 34.99},
		{"Coffee Beans", "Food", 14.99},
		{"Notebook", "Stationery", 9.99},
	}

	// Filter products based on keyword (case-insensitive search simulation)
	var results []Product
	keyword = html.EscapeString(keyword)

	for _, product := range allProducts {
		// Simple substring matching (in real app, use more sophisticated search)
		if keyword == "" || 
		   containsIgnoreCase(product.Name, keyword) || 
		   containsIgnoreCase(product.Category, keyword) {
			results = append(results, product)
		}
	}

	return results
}

// containsIgnoreCase checks if string contains substring (case-insensitive)
func containsIgnoreCase(s, substr string) bool {
	// Simple implementation for demonstration
	// In production, use strings.Contains with strings.ToLower
	for i := 0; i <= len(s)-len(substr); i++ {
		if len(s[i:]) >= len(substr) {
			match := true
			for j := 0; j < len(substr); j++ {
				if toLower(s[i+j]) != toLower(substr[j]) {
					match = false
					break
				}
			}
			if match {
				return true
			}
		}
	}
	return false
}

// toLower converts a byte to lowercase (ASCII only for simplicity)
func toLower(b byte) byte {
	if b >= 'A' && b <= 'Z' {
		return b + ('a' - 'A')
	}
	return b
}

// trackSearchAnalytics records search analytics for a keyword
func trackSearchAnalytics(keyword string) {
	if keyword == "" {
		return
	}

	now := time.Now()

	if analytics, exists := AnalyticsStore[keyword]; exists {
		// Update existing analytics
		analytics.SearchCount++
		analytics.LastSearch = now
	} else {
		// Create new analytics entry
		AnalyticsStore[keyword] = &SearchAnalytics{
			Keyword:     keyword,
			SearchCount: 1,
			FirstSearch: now,
			LastSearch:  now,
		}
	}
}

// getSearchAnalytics returns analytics for a specific keyword
func getSearchAnalytics(keyword string) *SearchAnalytics {
	if keyword == "" {
		return nil
	}
	return AnalyticsStore[keyword]
}

// getMostPopularKeyword returns the keyword with the highest search count
func getMostPopularKeyword() string {
	var popularKeyword string
	maxCount := 0

	for keyword, analytics := range AnalyticsStore {
		if analytics.SearchCount > maxCount {
			maxCount = analytics.SearchCount
			popularKeyword = keyword
		}
	}

	return popularKeyword
}

// AnalyticsHandler displays raw analytics data in JSON format
func AnalyticsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	// Convert analytics store to JSON
	jsonData, err := json.MarshalIndent(AnalyticsStore, "", "  ")
	if err != nil {
		http.Error(w, "Error generating analytics data", http.StatusInternalServerError)
		return
	}

	w.Write(jsonData)
}

func main() {
	// Register handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", AnalyticsHandler)

	// Start server
	fmt.Println("Server starting on http://localhost:8080")
	fmt.Println("Endpoints:")
	fmt.Println("  GET /search?keyword=... - Product search with analytics")
	fmt.Println("  GET /analytics - View raw analytics data")

	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

