// AnalyticsEvent represents a search analytics event
type AnalyticsEvent struct {
    Keyword     string    `json:"keyword"`
    Timestamp   time.Time `json:"timestamp"`
    UserAgent   string    `json:"user_agent"`
    RemoteAddr  string    `json:"remote_addr"`
}

// AnalyticsStore simulates an in-memory analytics store
var analyticsStore []AnalyticsEvent

// logAnalytics logs search events for analytics purposes
func logAnalytics(keyword, userAgent, remoteAddr string) {
    event := AnalyticsEvent{
        Keyword:    keyword,
        Timestamp:  time.Now(),
        UserAgent:  userAgent,
        RemoteAddr: remoteAddr,
    }
    analyticsStore = append(analyticsStore, event)

    // In a real application, you would persist this to a database
    fmt.Printf("Analytics logged: %s searched for '%s' at %s\n", 
        remoteAddr, keyword, event.Timestamp.Format(time.RFC3339))
}

// getAnalyticsSummary returns a summary of recent search analytics
func getAnalyticsSummary() string {
    if len(analyticsStore) == 0 {
        return "<p>No search analytics data available yet.</p>"
    }

    // Count keyword frequency
    keywordCount := make(map[string]int)
    for _, event := range analyticsStore {
        keywordCount[event.Keyword]++
    }

    // Build summary HTML
    var summary strings.Builder
    summary.WriteString("<h3>Search Analytics Summary</h3>")
    summary.WriteString("<p>Recent search activity:</p>")
    summary.WriteString("<ul>")

    for keyword, count := range keywordCount {
        summary.WriteString(fmt.Sprintf("<li>'%s': %d searches</li>", 
            html.EscapeString(keyword), count))
    }

    summary.WriteString("</ul>")
    summary.WriteString(fmt.Sprintf("<p>Total searches recorded: %d</p>", len(analyticsStore)))

    if len(analyticsStore) > 0 {
        latest := analyticsStore[len(analyticsStore)-1]
        summary.WriteString(fmt.Sprintf("<p>Latest search: '%s' at %s</p>",
            html.EscapeString(latest.Keyword),
            latest.Timestamp.Format("2006-01-02 15:04:05")))
    }

    return summary.String()
}

