}

// Product represents a product in search results
type Product struct {
    Name  string
    Price float64
}

// generateExampleProducts generates example products based on keyword
func generateExampleProducts(keyword string) []Product {
    if keyword == "" {
        return []Product{}
    }

    // Sample product database
    allProducts := []Product{
        {"Laptop Pro", 1299.99},
        {"Wireless Mouse", 29.99},
        {"Mechanical Keyboard", 89.99},
        {"Gaming Monitor", 349.99},
        {"USB-C Hub", 49.99},
        {"Noise Cancelling Headphones", 199.99},
        {"Smartphone Case", 19.99},
        {"Bluetooth Speaker", 79.99},
        {"External SSD 1TB", 129.99},
        {"Webcam HD", 59.99},
    }

    var results []Product
    keywordLower := strings.ToLower(keyword)

    for _, product := range allProducts {
        productNameLower := strings.ToLower(product.Name)
        if strings.Contains(productNameLower, keywordLower) {
            results = append(results, product)
        }
    }

    // If no matches found, return some default products
    if len(results) == 0 {
        results = []Product{
            {"Search Result 1", 99.99},
            {"Search Result 2", 149.99},
            {"Search Result 3", 199.99},
        }
    }

    return results
}

