import (
	"html"
	"net/http"
	"strings"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the search keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// If no keyword provided, use default text
	if keyword == "" {
		keyword = "No keyword provided"
	}

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Build the HTML response
	htmlResponse := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 40px;
            line-height: 1.6;
        }
        h2 {
            color: #333;
            border-bottom: 2px solid #4CAF50;
            padding-bottom: 10px;
        }
        .search-info {
            background-color: #f9f9f9;
            padding: 20px;
            border-radius: 5px;
            margin: 20px 0;
        }
        .results {
            margin-top: 30px;
        }
        .product {
            border: 1px solid #ddd;
            padding: 15px;
            margin: 10px 0;
            border-radius: 4px;
        }
    </style>
</head>
<body>
    <h2>Search Results: ` + escapedKeyword + `</h2>

    <div class="search-info">
        <p>You searched for: <strong>` + escapedKeyword + `</strong></p>
        <p>Found 0 matching products</p>
    </div>

    <div class="results">
        <p>No products found matching your search criteria.</p>
        <p>Try different keywords or check back later.</p>
    </div>

    <div style="margin-top: 30px; font-size: 0.9em; color: #666;">
        <p>Search performed at: ` + getCurrentTime() + `</p>
    </div>
</body>
</html>`

	// Write the HTML response
	w.Write([]byte(htmlResponse))
}

// Helper function to get current time (for demonstration purposes)
func getCurrentTime() string {
	return "Current time would be displayed here"
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	http.ListenAndServe(":8080", nil)
}

