	Keyword     string    `json:"keyword"`
	Timestamp   time.Time `json:"timestamp"`
	UserAgent   string    `json:"user_agent"`
	IPAddress  string    `json:"ip_address"`
	Path        string    `json:"path"`
}

// AnalyticsStore in-memory store for analytics events
var AnalyticsStore []AnalyticsEvent

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse query parameters
	query := r.URL.Query()
	keyword := query.Get("keyword")

	// Record analytics event
	recordAnalyticsEvent(r, keyword)

	// Generate HTML response
	htmlContent := generateHTMLResponse(keyword)

	// Write response
	fmt.Fprint(w, htmlContent)
}

// recordAnalyticsEvent records a search event for analytics
func recordAnalyticsEvent(r *http.Request, keyword string) {
	// Get client IP (simplified - in production use proper IP extraction)
	ip := r.RemoteAddr

	// Create analytics event
	event := AnalyticsEvent{
		Keyword:    keyword,
		Timestamp:  time.Now(),
		UserAgent:  r.UserAgent(),
		IPAddress: ip,
		Path:       r.URL.Path,
	}

	// Store the event
	AnalyticsStore = append(AnalyticsStore, event)

	// Log the event (optional)
	fmt.Printf("Search analytics recorded: %s - %s\n", keyword, event.Timestamp.Format(time.RFC3339))
