		}
	}

	return html
}

// HandleAnalyticsData returns analytics data as JSON (optional endpoint)
func HandleAnalyticsData(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(AnalyticsStore)
}

func main() {
	// Initialize analytics store
	AnalyticsStore = make([]AnalyticsEvent, 0)

	// Register handlers
	http.HandleFunc("/search", HandleProductSearch)
	http.HandleFunc("/analytics", HandleAnalyticsData)

	// Root redirect to search page
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
