func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get search keyword from URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// If keyword is empty, show a default message
	displayKeyword := escapedKeyword
	if strings.TrimSpace(keyword) == "" {
		displayKeyword = "No keyword provided"
	}

	// Generate HTML response
	htmlContent := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 40px;
            line-height: 1.6;
        }
        .container {
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 5px;
            background-color: #f9f9f9;
        }
        h2 {
            color: #333;
            border-bottom: 2px solid #4CAF50;
            padding-bottom: 10px;
        }
        .search-info {
            background-color: #e8f5e9;
            padding: 15px;
            border-radius: 4px;
            margin: 20px 0;
        }
        .timestamp {
            color: #666;
            font-size: 0.9em;
            margin-top: 20px;
        }
        .instructions {
            color: #555;
            font-style: italic;
            margin-top: 30px;
            padding: 10px;
            background-color: #f0f0f0;
            border-radius: 4px;
        }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: ` + displayKeyword + `</h2>

        <div class="search-info">
            <p><strong>Search Details:</strong></p>
            <ul>
                <li><strong>Keyword:</strong> ` + displayKeyword + `</li>
                <li><strong>Search Time:</strong> ` + time.Now().Format("2006-01-02 15:04:05") + `</li>
                <li><strong>Request Method:</strong> ` + r.Method + `</li>
            </ul>
        </div>

        <div class="search-results">
            <h3>Sample Products (for demonstration)</h3>
            <p>This is a demonstration of the product search results page.</p>
            <p>In a real application, this would display actual product search results.</p>
        </div>

        <div class="timestamp">
            Page generated at: ` + time.Now().Format("15:04:05.000") + `
        </div>

        <div class="instructions">
            <p><strong>Usage:</strong> Add ?keyword=your_search_term to the URL to search for products.</p>
            <p>Example: <code>/search?keyword=laptop</code></p>
